import { z } from 'zod';

/** Validated billing line item */
const LineItemSchema = z.object({
  productId: z.string().min(1),
  quantity: z.number().int().positive(),
  unitPrice: z.number().positive(),
  description: z.string().max(200),
});

/** Validated billing request */
const BillingRequestSchema = z.object({
  customerId: z.string().min(1),
  lineItems: z.array(LineItemSchema).min(1).max(50),
  currency: z.enum(['USD', 'EUR', 'GBP']),
  idempotencyKey: z.string().uuid(),
  metadata: z.record(z.string()).optional(),
});

type BillingRequest = z.infer<typeof BillingRequestSchema>;

interface BillingResult {
  invoiceId: string;
  total: number;
  currency: string;
  status: 'created' | 'pending' | 'paid' | 'failed';
  createdAt: string;
}

/**
 * Create a new billing invoice with full input validation
 * and idempotency protection.
 */
export async function createInvoice(input: unknown): Promise<BillingResult> {
  const parsed = BillingRequestSchema.parse(input);

  // Check idempotency — return existing invoice if key was already used
  const existing = await findByIdempotencyKey(parsed.idempotencyKey);
  if (existing) return existing;

  // Calculate total with proper decimal handling
  const total = parsed.lineItems.reduce(
    (sum, item) => sum + Math.round(item.unitPrice * item.quantity * 100) / 100,
    0,
  );

  if (total <= 0) {
    throw new Error('Invoice total must be positive');
  }

  const invoice: BillingResult = {
    invoiceId: `inv_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    total: Math.round(total * 100) / 100,
    currency: parsed.currency,
    status: 'created',
    createdAt: new Date().toISOString(),
  };

  await persistInvoice(invoice, parsed.idempotencyKey);
  return invoice;
}

